package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testIsLineBreak_Character_null() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        Boolean result = (Boolean) method.invoke(null, (Object) null);
        assertFalse(result);
    }

    @Test
    void testIsLineBreak_Character_withLineBreakChars() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);

        assertTrue((Boolean) method.invoke(null, Character.valueOf('\r')));
        assertTrue((Boolean) method.invoke(null, Character.valueOf('\n')));
    }

    @Test
    void testIsLineBreak_Character_withNonLineBreakChar() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);

        assertFalse((Boolean) method.invoke(null, Character.valueOf('a')));
        assertFalse((Boolean) method.invoke(null, Character.valueOf(' ')));
        assertFalse((Boolean) method.invoke(null, Character.valueOf('\t')));
    }

    @Test
    void testIsLineBreak_char_withLineBreakChars() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);

        // When invoking with primitive char, wrap in Object[] to avoid varargs confusion
        assertTrue((Boolean) method.invoke(null, (Object) new Character('\r')));
        assertTrue((Boolean) method.invoke(null, (Object) new Character('\n')));
    }

    @Test
    void testIsLineBreak_char_withNonLineBreakChar() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);

        assertFalse((Boolean) method.invoke(null, (Object) new Character('a')));
        assertFalse((Boolean) method.invoke(null, (Object) new Character(' ')));
        assertFalse((Boolean) method.invoke(null, (Object) new Character('\t')));
    }
}
